const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// ---------------------------------------------------------------------------
// Security middleware
// ---------------------------------------------------------------------------

// Set secure HTTP headers (removes X-Powered-By, adds CSP, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a strict size limit to prevent DoS
app.use(express.json({ limit: '10kb' }));

// Parse URL-encoded bodies with a strict size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Global rate limiter — 100 requests per 15-minute window per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// ---------------------------------------------------------------------------
// Request logging (basic — swap for morgan/pino in production)
// ---------------------------------------------------------------------------
app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - start;
    console.log(
      `${new Date().toISOString()} ${req.method} ${req.originalUrl} ${res.statusCode} ${duration}ms`
    );
  });
  next();
});

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const allowedParams = new Set(['id', 'name']);
  const unknownParams = Object.keys(req.query).filter(
    (key) => !allowedParams.has(key)
  );

  if (unknownParams.length > 0) {
    return res.status(400).json({
      error: 'Invalid query parameters',
      invalid: unknownParams,
    });
  }

  // Example: validate "id" is a positive integer when provided
  if (req.query.id !== undefined) {
    const id = Number(req.query.id);
    if (!Number.isInteger(id) || id <= 0) {
      return res.status(400).json({
        error: 'Parameter "id" must be a positive integer',
      });
    }
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json(users);
});

// ---------------------------------------------------------------------------
// 404 handler — catch unmatched routes
// ---------------------------------------------------------------------------
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// ---------------------------------------------------------------------------
// Global error handler — never leak stack traces to the client
// ---------------------------------------------------------------------------
app.use((err, _req, res, _next) => {
  console.error(`[ERROR] ${new Date().toISOString()}`, err.message, err.stack);

  // Send a generic message; never expose internals
  res.status(err.status || 500).json({
    error:
      process.env.NODE_ENV === 'production'
        ? 'Internal server error'
        : err.message,
  });
});

// ---------------------------------------------------------------------------
// Start server
// ---------------------------------------------------------------------------
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

